def preprocess(df):
    import pandas as pd
    if 'Name' in df.columns:
        df['Title'] = df['Name'].str.extract(r', (\w+)\.', expand=False)
        title_map = {'Mr': 0, 'Miss': 1, 'Mrs': 2, 'Master': 3}
        df['Title'] = df['Title'].map(title_map).fillna(4).astype(int)
    return df

def preprocess(df):
    import pandas as pd
    if 'SibSp' in df.columns and 'Parch' in df.columns:
        df['FamilySize'] = df['SibSp'] + df['Parch'] + 1
        df['IsAlone'] = (df['FamilySize'] == 1).astype(int)
    if 'Age' in df.columns:
        df['Age'] = df['Age'].fillna(df['Age'].median())
        df['AgeBin'] = pd.cut(df['Age'], bins=5, labels=False)
    return df

def preprocess(df):
    import pandas as pd
    if 'Cabin' in df.columns:
        df['Deck'] = df['Cabin'].str[0].map({'A':1,'B':2,'C':3,'D':4,'E':5,'F':6,'G':7,'T':8}).fillna(0).astype(int)
    return df

def preprocess(df):
    import pandas as pd
    if 'Ticket' in df.columns:
        df['TicketPrefix'] = df['Ticket'].str.extract(r'^([A-Za-z]+)', expand=False).fillna('NONE')
        df['TicketPrefix'] = df['TicketPrefix'].astype('category').cat.codes
    if 'Embarked' in df.columns:
        df['Embarked'] = df['Embarked'].fillna(df['Embarked'].mode()[0])
    if 'Fare' in df.columns and 'SibSp' in df.columns and 'Parch' in df.columns:
        family_size = df['SibSp'] + df['Parch'] + 1
        df['FarePerPerson'] = df['Fare'] / family_size
    return df

def preprocess(df):
    import pandas as pd
    import numpy as np
    numeric_cols = df.select_dtypes(include='number').columns.tolist()
    for col in numeric_cols:
        if col in df.columns:
            df[col] = df[col].fillna(df[col].median())
            if df[col].min() > 0 and df[col].skew() > 1:
                df[col] = np.log1p(df[col])
    return df

def preprocess(df):
    import pandas as pd
    import numpy as np
    if 'DebtAmount' in df.columns and 'Income' in df.columns:
        df['DebtToIncome'] = df['DebtAmount'] / (df['Income'] + 1e-6)
    if 'Balance' in df.columns and 'CreditLimit' in df.columns:
        df['Utilization'] = df['Balance'] / (df['CreditLimit'] + 1e-6)
    if 'PastDue' in df.columns:
        df['AnyDelinquency'] = (df['PastDue'] > 0).astype(int)
    return df

def preprocess(df):
    import pandas as pd
    for col in ['Age', 'Income', 'Balance']:
        if col in df.columns:
            df[f'{col}Bin'] = pd.qcut(df[col].fillna(df[col].median()), q=5, labels=False, duplicates='drop')
    return df

def preprocess(df):
    import pandas as pd
    for col in ['LoanPurpose', 'EmploymentType']:
        if col in df.columns:
            freq = df[col].value_counts(normalize=True)
            rare = freq[freq < 0.01].index
            df[col] = df[col].apply(lambda x: 'Other' if x in rare else x)
    return df

def preprocess(df):
    import pandas as pd
    import numpy as np
    if 'TotalBsmtSF' in df.columns and '1stFlrSF' in df.columns and '2ndFlrSF' in df.columns:
        df['TotalSF'] = df['TotalBsmtSF'] + df['1stFlrSF'] + df['2ndFlrSF']
    for col in ['LotArea', 'GrLivArea']:
        if col in df.columns and df[col].min() > 0:
            df[col] = np.log1p(df[col])
    return df

def preprocess(df):
    import pandas as pd
    if 'YrSold' in df.columns and 'YearBuilt' in df.columns:
        df['HouseAge'] = df['YrSold'] - df['YearBuilt']
    if 'YrSold' in df.columns and 'YearRemodAdd' in df.columns:
        df['RemodelAge'] = df['YrSold'] - df['YearRemodAdd']
    if 'OverallQual' in df.columns and 'OverallCond' in df.columns:
        df['QualCondProduct'] = df['OverallQual'] * df['OverallCond']
    return df

def preprocess(df):
    import pandas as pd
    if 'TotRmsAbvGrd' in df.columns and 'TotalBsmtSF' in df.columns:
        total_sf = df.get('GrLivArea', 1)
        df['RoomsPerSF'] = df['TotRmsAbvGrd'] / (total_sf + 1)
    if 'FullBath' in df.columns and 'HalfBath' in df.columns:
        df['TotalBaths'] = df['FullBath'] + 0.5 * df['HalfBath']
    if 'LotFrontage' in df.columns and 'Neighborhood' in df.columns:
        df['LotFrontage'] = df.groupby('Neighborhood')['LotFrontage'].transform(lambda x: x.fillna(x.median()))
    return df

def preprocess(df):
    import pandas as pd
    qual_map = {'Po': 1, 'Fa': 2, 'TA': 3, 'Gd': 4, 'Ex': 5}
    for col in ['ExterQual', 'ExterCond', 'BsmtQual', 'KitchenQual', 'HeatingQC']:
        if col in df.columns:
            df[col] = df[col].map(qual_map).fillna(0).astype(int)
    return df

def preprocess(df):
    import pandas as pd
    if 'headline' in df.columns:
        df['headline_len'] = df['headline'].str.len().fillna(0).astype(int)
        df['headline_words'] = df['headline'].str.split().str.len().fillna(0).astype(int)
    if 'short_description' in df.columns:
        df['short_description'] = df['short_description'].fillna('')
    return df

def preprocess(df):
    import pandas as pd
    import re
    if 'headline' in df.columns:
        df['upper_ratio'] = df['headline'].apply(lambda x: sum(1 for c in str(x) if c.isupper()) / (len(str(x)) + 1))
        df['punct_count'] = df['headline'].apply(lambda x: len(re.findall(r'[!?.,;:]', str(x))))
    if 'date' in df.columns:
        df['pub_hour'] = pd.to_datetime(df['date'], errors='coerce').dt.hour.fillna(-1).astype(int)
    return df

def preprocess(df):
    import pandas as pd
    if 'headline' in df.columns and 'short_description' in df.columns:
        df['full_text'] = df['headline'].fillna('') + ' ' + df['short_description'].fillna('')
        df['full_text_len'] = df['full_text'].str.len().fillna(0).astype(int)
    return df

def preprocess(df):
    import pandas as pd
    numeric_cols = df.select_dtypes(include='number').columns.tolist()
    for col in numeric_cols:
        col_min = df[col].min()
        col_max = df[col].max()
        if col_max > col_min:
            df[col] = (df[col] - col_min) / (col_max - col_min)
    return df
